import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";

const Register = () => {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    name: "",
    email: "",
    password: "",
    confirmPassword: ""
  });

  const [showPassword, setShowPassword] = useState(false);

  // 🔥 IMAGE STATE
  const [image, setImage] = useState(null);
  const [preview, setPreview] = useState("https://i.pravatar.cc/100");
  const [uploading, setUploading] = useState(false);

  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  // 🔥 IMAGE CHANGE
  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setImage(file);

    const reader = new FileReader();
    reader.onloadend = () => {
      setPreview(reader.result);
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!form.name || !form.email || !form.password) {
      alert("All fields required ❌");
      return;
    }

    if (form.password !== form.confirmPassword) {
      alert("Passwords do not match ❌");
      return;
    }

    try {
      setUploading(true);

      const res = await axios.post(
        "http://localhost:5001/api/auth/register",
        {
          name: form.name,
          email: form.email,
          password: form.password
        }
      );

      localStorage.setItem("userId", res.data.userId);
      localStorage.setItem("userName", res.data.name);

      setUploading(false);

      alert("Register Successful ✅");
      navigate("/dashboard");

    } catch (err) {
      setUploading(false);
      alert(err.response?.data || "Error ❌");
    }
  };

  const particles = Array.from({ length: 12 });

  return (
    <div className="relative min-h-screen flex items-center justify-center overflow-hidden bg-[#020617] px-4">

      {/* BG */}
      <motion.div
        animate={{ x: [0, 120, -120, 0], y: [0, -120, 120, 0] }}
        transition={{ duration: 18, repeat: Infinity }}
        className="absolute w-[500px] h-[500px] bg-purple-500/30 rounded-full blur-[120px] top-[-100px] left-[-100px]"
      />

      <motion.div
        animate={{ x: [0, -120, 120, 0], y: [0, 120, -120, 0] }}
        transition={{ duration: 20, repeat: Infinity }}
        className="absolute w-[400px] h-[400px] bg-blue-500/30 rounded-full blur-[120px] bottom-[-100px] right-[-100px]"
      />

      {/* PARTICLES */}
      <div className="absolute inset-0">
        {particles.map((_, i) => (
          <motion.div
            key={i}
            animate={{ y: [0, -25, 0] }}
            transition={{ duration: 4 + i, repeat: Infinity }}
            className="absolute w-2 h-2 bg-white/20 rounded-full"
            style={{
              top: `${Math.random() * 100}%`,
              left: `${Math.random() * 100}%`
            }}
          />
        ))}
      </div>

      {/* CARD */}
      <motion.div
        initial={{ opacity: 0, y: 60, scale: 0.9 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        className="relative z-10 backdrop-blur-2xl bg-white/10 border border-white/20 shadow-xl rounded-3xl p-6 w-full max-w-md text-white"
      >

        <h2 className="text-3xl font-bold text-center mb-6">
          Create Account
        </h2>

        {/* 🔥 IMAGE UPLOAD */}
        <div className="flex flex-col items-center mb-6">

          <div className="relative">
            <img
              src={preview}
              alt="preview"
              className="w-24 h-24 rounded-full object-cover border-4 border-white shadow-lg"
            />

            {/* Upload loader */}
            {uploading && (
              <div className="absolute inset-0 bg-black/60 flex items-center justify-center rounded-full">
                <div className="w-6 h-6 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
              </div>
            )}
          </div>

          <label className="mt-3 text-sm cursor-pointer text-indigo-400 hover:underline">
            Upload Photo
            <input
              type="file"
              accept="image/*"
              onChange={handleImageChange}
              className="hidden"
            />
          </label>

        </div>

        <form className="space-y-5" onSubmit={handleSubmit}>

          <input
            type="text"
            name="name"
            placeholder="Full Name"
            value={form.name}
            onChange={handleChange}
            required
            className="w-full px-4 py-3 rounded-xl bg-white/10 border border-white/20"
          />

          <input
            type="email"
            name="email"
            placeholder="Email Address"
            value={form.email}
            onChange={handleChange}
            required
            className="w-full px-4 py-3 rounded-xl bg-white/10 border border-white/20"
          />

          {/* PASSWORD */}
          <div className="relative">
            <input
              type={showPassword ? "text" : "password"}
              name="password"
              placeholder="Enter password"
              value={form.password}
              onChange={handleChange}
              required
              className="w-full px-4 py-3 rounded-xl bg-white/10 border border-white/20"
            />

            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              className="absolute right-3 top-3 text-white/70"
            >
              👁
            </button>
          </div>

          <input
            type={showPassword ? "text" : "password"}
            name="confirmPassword"
            placeholder="Confirm Password"
            value={form.confirmPassword}
            onChange={handleChange}
            required
            className="w-full px-4 py-3 rounded-xl bg-white/10 border border-white/20"
          />

          <motion.button
            whileTap={{ scale: 0.95 }}
            type="submit"
            className="w-full py-3 rounded-xl bg-gradient-to-r from-indigo-500 to-purple-500 font-semibold"
          >
            Register
          </motion.button>

        </form>

        <p className="text-center text-sm mt-6">
          Already have an account?
          <span
            onClick={() => navigate("/login")}
            className="ml-1 text-indigo-400 cursor-pointer"
          >
            Login
          </span>
        </p>

      </motion.div>

    </div>
  );
};

export default Register;
